// Parse Ecowitt payload (form-urlencoded o JSON), genera points InfluxDB,
// e popola global.soil_moisture_cache letto dalla decision loop.

let raw = msg.payload;
if (typeof raw === 'string') {
    const parsed = {};
    for (const pair of raw.split('&')) {
        if (!pair) continue;
        const eq = pair.indexOf('=');
        if (eq < 0) continue;
        const k = decodeURIComponent(pair.slice(0, eq));
        const v = decodeURIComponent(pair.slice(eq + 1).replace(/\+/g, ' '));
        parsed[k] = v;
    }
    raw = parsed;
}
if (!raw || typeof raw !== 'object') {
    node.warn('Payload non riconosciuto, scarto');
    return null;
}

const CHANNELS = [1, 2, 3, 4];
const BATTERY_OK_THRESHOLD = 1.1;
const out = [];
const cache = global.get('soil_moisture_cache') || {};
const now = Date.now();

for (const ch of CHANNELS) {
    const mRaw = raw['soilmoisture' + ch];
    if (mRaw === undefined || mRaw === null || mRaw === '') continue;
    const value = Number(mRaw);
    if (!Number.isFinite(value)) continue;

    const battRaw = raw['soilbatt' + ch];
    const battery_voltage = Number(battRaw);
    const battery_ok = Number.isFinite(battery_voltage) && battery_voltage >= BATTERY_OK_THRESHOLD;
    const sensor_id = 'WH51_0' + ch;

    out.push([
        { value, battery_voltage: Number.isFinite(battery_voltage) ? battery_voltage : 0, battery_ok },
        { sensor_id, aiuola: 'test', position: 'test' }
    ]);

    cache[sensor_id] = { value, ts: now, battery_ok };
}

global.set('soil_moisture_cache', cache);

if (out.length === 0) {
    node.warn('Nessun canale soilmoisture1..4 valido nel payload');
    return null;
}

return { payload: out, measurement: 'soil_moisture' };

msg.statusCode = 204;
msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Access-Control-Max-Age': '600'
};
msg.payload = '';
return msg;

// Valida :action e costruisce payload MQTT.
// Marca origine in global.last_cmd_source per il tracking irrigation_events.
// Step 5: supporta duration_seconds nel body per apertura manuale temporizzata.
const raw = ((msg.req && msg.req.params && msg.req.params.action) || '').toLowerCase();
const MAP = { on: 'ON', off: 'OFF', toggle: 'TOGGLE' };
const mqttState = MAP[raw];

msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type'
};

if (!mqttState) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: `invalid action '${raw}', use on/off/toggle` };
    node.status({ fill: 'red', shape: 'ring', text: `400 '${raw}'` });
    return [null, msg];
}

// Step 5: parsing duration_seconds dal body (solo per ON).
let durationApplied = null;
if (mqttState === 'ON') {
    const cfg = global.get('irrigation_config') || {};
    const safety = (cfg.irrigation && cfg.irrigation.safety_timeout_seconds) || 900;
    const body = msg.req && msg.req.body;
    let d = body && body.duration_seconds;
    if (d !== undefined && d !== null) {
        d = Number(d);
        if (!Number.isFinite(d) || d < 60) {
            msg.statusCode = 400;
            msg.payload = { ok: false, error: 'duration_seconds must be a number >= 60' };
            node.status({ fill: 'red', shape: 'ring', text: '400 dur' });
            return [null, msg];
        }
        durationApplied = Math.min(d, safety);
    }
    global.set('valve_runtime', { requested_duration: durationApplied, requested_at: Date.now() });
}

const mqttMsg = {
    topic: 'zigbee2mqtt/SWV_valvola/set',
    payload: { state: mqttState }
};

// Comando manuale: globalizza il source per il tracking dell'evento.
if (mqttState === 'ON') global.set('last_cmd_source', 'manual');

msg.statusCode = 200;
msg.payload = { ok: true, action: raw, sent: mqttState };
if (durationApplied !== null) msg.payload.duration_seconds_applied = durationApplied;
node.status({ fill: 'blue', shape: 'dot', text: `${raw} @ ${new Date().toISOString().substr(11, 8)}` });

return [mqttMsg, msg];

// Mantiene global.valve_state_runtime per la decision loop.
// Cancella anche awaiting_confirmation se la conferma attesa e' arrivata.
// Step 5: traccia last_change (transizione) e linkquality per /api/valve/state.
const p = msg.payload;
if (!p || typeof p !== 'object') return null;

if (p.state === 'ON' || p.state === 'OFF') {
    const prev = global.get('valve_state_runtime');
    if (prev !== p.state) {
        global.set('valve_last_change', Date.now());
    }
    global.set('valve_state_runtime', p.state);
    const awaiting = global.get('awaiting_confirmation');
    if (awaiting && awaiting.target === p.state) {
        global.set('awaiting_confirmation', null);
        global.set('valve_unreachable_consecutive', 0);
    }
}

// Cattura reachable per gating apertura.
if (typeof p.reachable === 'boolean') {
    global.set('valve_reachable', p.reachable);
}

// Step 5: linkquality (qualita' Zigbee) per /api/valve/state.
if (Number.isFinite(p.linkquality)) {
    global.set('valve_linkquality', Number(p.linkquality));
}

return null;

// Estrae campi e crea point InfluxDB con tag valve_id=SWV_01.
const p = msg.payload;
if (!p || typeof p !== 'object') return null;

const fields = { reachable: true };
if (p.state === 'ON' || p.state === 'OFF') fields.state = p.state;
if (Number.isFinite(p.battery)) fields.battery = Number(p.battery);
if (Number.isFinite(p.linkquality)) fields.linkquality = Number(p.linkquality);
if (p.current_device_status) fields.current_device_status = String(p.current_device_status);
if (Number.isFinite(p.flow)) fields.flow = Number(p.flow);

if (Object.keys(fields).length <= 1) return null;

return {
    payload: [fields, { valve_id: 'SWV_01' }],
    measurement: 'valve_state'
};

// Safety/auto-off timer: forza OFF dopo durata richiesta (default safety_timeout_seconds).
// Step 5: se global.valve_runtime.requested_duration e' settato, usa quello (clamp a SAFETY_S).
const cfg = global.get('irrigation_config') || {};
const SAFETY_S = (cfg.irrigation && cfg.irrigation.safety_timeout_seconds) || 900;
const state = msg.payload && msg.payload.state;

let h = context.get('timer');
if (h) { clearTimeout(h); context.set('timer', null); }

if (state === 'ON') {
    const runtime = global.get('valve_runtime') || {};
    const req = Number(runtime.requested_duration);
    const DURATION_S = (Number.isFinite(req) && req >= 60) ? Math.min(req, SAFETY_S) : SAFETY_S;
    const ms = DURATION_S * 1000;
    const fires_at = new Date(Date.now() + ms);
    // Salva opened_at per /api/valve/state (open_since_seconds, auto_close_in_seconds).
    global.set('valve_runtime', Object.assign({}, runtime, { opened_at: Date.now(), duration_seconds: DURATION_S }));
    const label = DURATION_S < SAFETY_S ? `manual ${DURATION_S}s` : `safety ${DURATION_S}s`;
    const handle = setTimeout(() => {
        node.warn(`AUTO-OFF ${DURATION_S}s: forcing OFF`);
        node.send({
            topic: 'zigbee2mqtt/SWV_valvola/set',
            payload: { state: 'OFF' },
            _safety: true
        });
        context.set('timer', null);
        node.status({ fill: 'red', shape: 'dot', text: `TIMEOUT @ ${new Date().toISOString().substr(11, 8)}` });
    }, ms);
    context.set('timer', handle);
    node.status({ fill: 'yellow', shape: 'dot', text: `armed ${label} (OFF @ ${fires_at.toISOString().substr(11, 5)})` });
} else if (state === 'OFF') {
    // Pulisci runtime di apertura.
    const runtime = global.get('valve_runtime') || {};
    if (runtime && runtime.opened_at) {
        global.set('valve_runtime', { requested_duration: null, opened_at: null, duration_seconds: null, last_close_at: Date.now() });
    }
    node.status({ fill: 'green', shape: 'dot', text: 'disarmed (OFF)' });
}

return null;

// Tracking irrigation_events 15-field schema. Triggera su transizioni ON/OFF.
// state=ON: cattura snapshot meteo/sensori per delta_moisture finale.
// state=OFF: calcola durata, delta, total_liters; aggiorna last_irrigation_at.
const p = msg.payload;
if (!p || typeof p !== 'object') return null;
const state = p.state;
const now = Date.now();
const cfg = global.get('irrigation_config') || {};

function sensorMean() {
    const cache = global.get('soil_moisture_cache') || {};
    const max_age_ms = ((cfg.sensors && cfg.sensors.max_age_seconds) || 1800) * 1000;
    const valid = Object.values(cache).filter(e => (now - e.ts) < max_age_ms).map(e => e.value);
    if (!valid.length) return { mean: null, count: 0, stddev: 0, high_var: false };
    const mean = valid.reduce((a, b) => a + b, 0) / valid.length;
    const variance = valid.reduce((s, v) => s + (v - mean) ** 2, 0) / valid.length;
    const stddev = Math.sqrt(variance);
    const stddev_warn = (cfg.sensors && cfg.sensors.stddev_warning_pct) || 25;
    return { mean: Number(mean.toFixed(2)), count: valid.length, stddev: Number(stddev.toFixed(2)), high_var: stddev > stddev_warn };
}

function weatherSnapshot() {
    const wc = global.get('weather_cache');
    const max_age_ms = ((cfg.weather && cfg.weather.cache_max_age_seconds) || 5400) * 1000;
    if (!wc || !wc.fetched_at) return { rain_forecast_mm: 0, weather_data_age_seconds: 0, weather_available: false };
    const age = now - wc.fetched_at;
    return {
        rain_forecast_mm: Number((wc.precip_next_24h_mm || 0).toFixed(2)),
        weather_data_age_seconds: Math.round(age / 1000),
        weather_available: age < max_age_ms
    };
}

if (state === 'ON') {
    const sensors = sensorMean();
    const weather = weatherSnapshot();
    const trigger = global.get('last_cmd_source') || 'manual';
    global.set('irrigation_open', {
        ts: now,
        avg_at_trigger: sensors.mean,
        sensor_count: sensors.count,
        sensors_high_variance: sensors.high_var,
        rain_forecast_mm: weather.rain_forecast_mm,
        weather_data_age_seconds: weather.weather_data_age_seconds,
        weather_available: weather.weather_available,
        trigger,
        dry_run: cfg.mode === 'dry_run'
    });
    global.set('in_progress', true);
    global.set('opened_at', now);
    return null;
}

if (state === 'OFF') {
    const open = global.get('irrigation_open');
    if (!open) return null;
    const sensors = sensorMean();
    const duration_s = Math.round((now - open.ts) / 1000);
    const delta = sensors.mean !== null && open.avg_at_trigger !== null ? Number((sensors.mean - open.avg_at_trigger).toFixed(2)) : 0;
    // total_liters: usa global.last_flow_m3h se valido (campo flow del SWV)
    const flow_m3h = Number(global.get('last_flow_m3h')) || 0;
    const total_liters = Number(((flow_m3h * 1000) * (duration_s / 3600)).toFixed(2));
    const reason = open.trigger === 'manual' ? 'comando manuale' : (open.trigger === 'emergency' ? 'emergency' : 'scheduled');

    global.set('irrigation_open', null);
    global.set('in_progress', false);
    global.set('opened_at', null);
    global.set('last_irrigation_at', now);
    global.set('last_cmd_source', null);

    return {
        payload: [
            {
                state: 'OFF',
                duration_seconds: duration_s,
                avg_moisture_at_trigger: open.avg_at_trigger || 0,
                avg_moisture_at_close: sensors.mean || 0,
                delta_moisture: delta,
                reason,
                rain_forecast_mm: open.rain_forecast_mm,
                weather_data_age_seconds: open.weather_data_age_seconds,
                weather_available: open.weather_available,
                sensor_count: open.sensor_count,
                sensors_high_variance: open.sensors_high_variance,
                total_liters,
                dry_run: open.dry_run
            },
            { trigger: open.trigger, valve_id: 'SWV_01' }
        ],
        measurement: 'irrigation_events'
    };
}

return null;

// Step 5: assembla risposta GET /api/valve/state.
const now = Date.now();
const state = global.get('valve_state_runtime');
const reachable = global.get('valve_reachable');
const linkquality = global.get('valve_linkquality');
const last_change = global.get('valve_last_change');
const runtime = global.get('valve_runtime') || {};
const cfg = global.get('irrigation_config') || {};
const max_duration = (cfg.irrigation && cfg.irrigation.safety_timeout_seconds) || 900;

let open_since_seconds = null;
let auto_close_in_seconds = null;
if (state === 'ON' && runtime.opened_at) {
    open_since_seconds = Math.round((now - runtime.opened_at) / 1000);
    const dur = runtime.duration_seconds || max_duration;
    auto_close_in_seconds = Math.max(0, dur - open_since_seconds);
}

msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = {
    valve_id: 'SWV_01',
    state: state || 'unknown',
    reachable: typeof reachable === 'boolean' ? reachable : null,
    linkquality: Number.isFinite(linkquality) ? linkquality : null,
    last_change: last_change || null,
    open_since_seconds,
    auto_close_in_seconds,
    max_duration_seconds: max_duration,
    requested_duration_seconds: runtime.duration_seconds || null
};
return msg;

// Parsa JSON config e popola global.irrigation_config.
// Se il file è mancante o corrotto, carica defaults hardcoded e logga warning.
const DEFAULTS = {
    irrigation: {
        soglia_apertura_pct: 40,
        soglia_chiusura_pct: 65,
        soglia_emergenza_pct: 25,
        cooldown_seconds: 7200,
        safety_timeout_seconds: 900,
        emergency_duration_seconds: 300,
        finestra_mattina: ['06:00', '08:00'],
        finestra_sera: ['19:00', '21:00'],
        polling_interval_seconds: 300,
        monitoring_interval_seconds: 60
    },
    weather: {
        polling_interval_seconds: 1800,
        cache_max_age_seconds: 5400,
        rain_threshold_mm: 5,
        rain_window_hours: 24,
        api_url: 'https://api.open-meteo.com/v1/forecast',
        lat: 45.71722434055733,
        lon: 9.733793667999565
    },
    valve: { command_timeout_seconds: 30, max_retries: 1, unreachable_alert_after: 3 },
    sensors: { max_age_seconds: 1800, min_quorum: 2, stddev_warning_pct: 25 },
    mode: 'dry_run',
    pause_until: null
};

let cfg;
try {
    cfg = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : msg.payload;
    if (!cfg || typeof cfg !== 'object' || !cfg.irrigation) throw new Error('invalid structure');
} catch (e) {
    node.warn(`Config load failed (${e.message}), using defaults`);
    cfg = DEFAULTS;
}
global.set('irrigation_config', cfg);
node.status({ fill: 'green', shape: 'dot', text: `loaded mode=${cfg.mode}` });
node.log(`Config loaded: mode=${cfg.mode}, soglia_apertura=${cfg.irrigation.soglia_apertura_pct}`);
return null;

msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.statusCode = 200;
msg.payload = global.get('irrigation_config') || {};
return msg;

// Estrae path e value dalla richiesta HTTP, delega a validateAndApply.
const pathRaw = (msg.req && msg.req.params && msg.req.params[0]) || '';
const path = pathRaw.split('/').filter(Boolean);
const value = msg.payload && msg.payload.value;

msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };

const cfg = global.get('irrigation_config');
if (!cfg) {
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'config not loaded yet' };
    return [msg, null];
}

const result = validateAndApply(path, value, cfg);
if (!result.ok) {
    msg.statusCode = 400;
    msg.payload = { ok: false, key: path.join('.'), error: result.error };
    return [msg, null];
}

global.set('irrigation_config', result.newCfg);
msg.statusCode = 200;
msg.payload = { ok: true, key: path.join('.'), value };
node.status({ fill: 'blue', shape: 'dot', text: `set ${path.join('.')} @ ${new Date().toISOString().substr(11, 8)}` });

// Output 2: persisti su file
const persistMsg = { payload: JSON.stringify(result.newCfg, null, 2), filename: '/data/irrigation_config.json' };
return [msg, persistMsg];

function validateAndApply(path, value, cfg) {
    if (!path.length) return { ok: false, error: 'empty path' };
    const dot = path.join('.');
    const PATHS = {
        'irrigation.soglia_apertura_pct': v => typeof v === 'number' && v > 0 && v < 100,
        'irrigation.soglia_chiusura_pct': v => typeof v === 'number' && v > 0 && v < 100,
        'irrigation.soglia_emergenza_pct': v => typeof v === 'number' && v > 0 && v < 100,
        'irrigation.cooldown_seconds': v => Number.isFinite(v) && v >= 60,
        'irrigation.safety_timeout_seconds': v => Number.isFinite(v) && v >= 60,
        'irrigation.emergency_duration_seconds': v => Number.isFinite(v) && v >= 30,
        'irrigation.polling_interval_seconds': v => Number.isFinite(v) && v >= 30,
        'irrigation.monitoring_interval_seconds': v => Number.isFinite(v) && v >= 10,
        'irrigation.finestra_mattina': v => Array.isArray(v) && v.length === 2 && v.every(s => /^\d{2}:\d{2}$/.test(s)) && v[0] < v[1],
        'irrigation.finestra_sera': v => Array.isArray(v) && v.length === 2 && v.every(s => /^\d{2}:\d{2}$/.test(s)) && v[0] < v[1],
        'weather.polling_interval_seconds': v => Number.isFinite(v) && v >= 60,
        'weather.cache_max_age_seconds': v => Number.isFinite(v) && v >= 60,
        'weather.rain_threshold_mm': v => Number.isFinite(v) && v >= 0,
        'weather.rain_window_hours': v => Number.isInteger(v) && v >= 1 && v <= 72,
        'weather.api_url': v => typeof v === 'string' && v.startsWith('http'),
        'weather.lat': v => Number.isFinite(v) && v >= -90 && v <= 90,
        'weather.lon': v => Number.isFinite(v) && v >= -180 && v <= 180,
        'valve.command_timeout_seconds': v => Number.isFinite(v) && v >= 5,
        'valve.max_retries': v => Number.isInteger(v) && v >= 0 && v <= 5,
        'valve.unreachable_alert_after': v => Number.isInteger(v) && v >= 1,
        'sensors.max_age_seconds': v => Number.isFinite(v) && v >= 60,
        'sensors.min_quorum': v => Number.isInteger(v) && v >= 1 && v <= 10,
        'sensors.stddev_warning_pct': v => Number.isFinite(v) && v >= 0 && v <= 100,
        'mode': v => ['auto', 'paused', 'dry_run'].includes(v),
        'pause_until': v => v === null || (typeof v === 'string' && !isNaN(Date.parse(v)))
    };
    const validator = PATHS[dot];
    if (!validator) return { ok: false, error: `unknown config path: ${dot}` };
    if (!validator(value)) return { ok: false, error: `invalid value for ${dot}` };

    const newCfg = JSON.parse(JSON.stringify(cfg));
    let target = newCfg;
    for (let i = 0; i < path.length - 1; i++) {
        if (!(path[i] in target)) return { ok: false, error: `missing parent: ${path.slice(0, i + 1).join('.')}` };
        target = target[path[i]];
    }
    target[path[path.length - 1]] = value;

    const irr = newCfg.irrigation;
    if (irr.soglia_emergenza_pct >= irr.soglia_apertura_pct) return { ok: false, error: 'emergenza must be < apertura' };
    if (irr.soglia_apertura_pct >= irr.soglia_chiusura_pct) return { ok: false, error: 'apertura must be < chiusura' };
    if (irr.emergency_duration_seconds >= irr.safety_timeout_seconds) return { ok: false, error: 'emergency_duration must be < safety_timeout' };
    if (newCfg.weather.cache_max_age_seconds <= newCfg.weather.polling_interval_seconds) return { ok: false, error: 'weather cache_max_age must be > polling_interval' };

    return { ok: true, newCfg };
}

// Path da topic: orto/config/set/<rest> -> rest dot.path
const topic = msg.topic || '';
const prefix = 'orto/config/set/';
if (!topic.startsWith(prefix)) return null;
const pathStr = topic.slice(prefix.length);
const path = pathStr.split('/').filter(Boolean);

// Coerce payload: numero/booleano/JSON string/array
let value = msg.payload;
if (typeof value === 'string') {
    const t = value.trim();
    if (/^-?\d+(\.\d+)?$/.test(t)) value = Number(t);
    else if (t === 'true') value = true;
    else if (t === 'false') value = false;
    else if (t === 'null') value = null;
    else if (t.startsWith('[') || t.startsWith('{')) {
        try { value = JSON.parse(t); } catch (e) { /* keep string */ }
    }
}

const cfg = global.get('irrigation_config');
if (!cfg) {
    return { topic: 'orto/config/result', payload: { ok: false, key: pathStr, error: 'config not loaded' } };
}

const result = validateAndApply(path, value, cfg);
if (!result.ok) {
    node.status({ fill: 'red', shape: 'ring', text: `400 ${pathStr}` });
    return { topic: 'orto/config/result', payload: { ok: false, key: pathStr.split('/').join('.'), error: result.error } };
}
global.set('irrigation_config', result.newCfg);
node.status({ fill: 'blue', shape: 'dot', text: `set ${pathStr} @ ${new Date().toISOString().substr(11, 8)}` });

const replyMsg = { topic: 'orto/config/result', payload: { ok: true, key: pathStr.split('/').join('.'), value } };
const persistMsg = { payload: JSON.stringify(result.newCfg, null, 2), filename: '/data/irrigation_config.json' };
return [replyMsg, persistMsg];

function validateAndApply(path, value, cfg) {
    if (!path.length) return { ok: false, error: 'empty path' };
    const dot = path.join('.');
    const PATHS = {
        'irrigation.soglia_apertura_pct': v => typeof v === 'number' && v > 0 && v < 100,
        'irrigation.soglia_chiusura_pct': v => typeof v === 'number' && v > 0 && v < 100,
        'irrigation.soglia_emergenza_pct': v => typeof v === 'number' && v > 0 && v < 100,
        'irrigation.cooldown_seconds': v => Number.isFinite(v) && v >= 60,
        'irrigation.safety_timeout_seconds': v => Number.isFinite(v) && v >= 60,
        'irrigation.emergency_duration_seconds': v => Number.isFinite(v) && v >= 30,
        'irrigation.polling_interval_seconds': v => Number.isFinite(v) && v >= 30,
        'irrigation.monitoring_interval_seconds': v => Number.isFinite(v) && v >= 10,
        'irrigation.finestra_mattina': v => Array.isArray(v) && v.length === 2 && v.every(s => /^\d{2}:\d{2}$/.test(s)) && v[0] < v[1],
        'irrigation.finestra_sera': v => Array.isArray(v) && v.length === 2 && v.every(s => /^\d{2}:\d{2}$/.test(s)) && v[0] < v[1],
        'weather.polling_interval_seconds': v => Number.isFinite(v) && v >= 60,
        'weather.cache_max_age_seconds': v => Number.isFinite(v) && v >= 60,
        'weather.rain_threshold_mm': v => Number.isFinite(v) && v >= 0,
        'weather.rain_window_hours': v => Number.isInteger(v) && v >= 1 && v <= 72,
        'weather.api_url': v => typeof v === 'string' && v.startsWith('http'),
        'weather.lat': v => Number.isFinite(v) && v >= -90 && v <= 90,
        'weather.lon': v => Number.isFinite(v) && v >= -180 && v <= 180,
        'valve.command_timeout_seconds': v => Number.isFinite(v) && v >= 5,
        'valve.max_retries': v => Number.isInteger(v) && v >= 0 && v <= 5,
        'valve.unreachable_alert_after': v => Number.isInteger(v) && v >= 1,
        'sensors.max_age_seconds': v => Number.isFinite(v) && v >= 60,
        'sensors.min_quorum': v => Number.isInteger(v) && v >= 1 && v <= 10,
        'sensors.stddev_warning_pct': v => Number.isFinite(v) && v >= 0 && v <= 100,
        'mode': v => ['auto', 'paused', 'dry_run'].includes(v),
        'pause_until': v => v === null || (typeof v === 'string' && !isNaN(Date.parse(v)))
    };
    const validator = PATHS[dot];
    if (!validator) return { ok: false, error: `unknown config path: ${dot}` };
    if (!validator(value)) return { ok: false, error: `invalid value for ${dot}` };

    const newCfg = JSON.parse(JSON.stringify(cfg));
    let target = newCfg;
    for (let i = 0; i < path.length - 1; i++) {
        if (!(path[i] in target)) return { ok: false, error: `missing parent: ${path.slice(0, i + 1).join('.')}` };
        target = target[path[i]];
    }
    target[path[path.length - 1]] = value;

    const irr = newCfg.irrigation;
    if (irr.soglia_emergenza_pct >= irr.soglia_apertura_pct) return { ok: false, error: 'emergenza must be < apertura' };
    if (irr.soglia_apertura_pct >= irr.soglia_chiusura_pct) return { ok: false, error: 'apertura must be < chiusura' };
    if (irr.emergency_duration_seconds >= irr.safety_timeout_seconds) return { ok: false, error: 'emergency_duration must be < safety_timeout' };
    if (newCfg.weather.cache_max_age_seconds <= newCfg.weather.polling_interval_seconds) return { ok: false, error: 'weather cache_max_age must be > polling_interval' };

    return { ok: true, newCfg };
}

// Snapshot dello stato runtime: valvola, irrigazione in corso, mode, weather cache.
const cfg = global.get('irrigation_config') || {};
const now = Date.now();
const wc = global.get('weather_cache');
const weather_age_s = wc ? Math.round((now - wc.fetched_at) / 1000) : null;

msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.statusCode = 200;
msg.payload = {
    mode: cfg.mode,
    pause_until: cfg.pause_until,
    valve_state_runtime: global.get('valve_state_runtime'),
    valve_reachable: global.get('valve_reachable'),
    valve_unreachable_consecutive: global.get('valve_unreachable_consecutive') || 0,
    in_progress: global.get('in_progress') || false,
    opened_at: global.get('opened_at'),
    last_irrigation_at: global.get('last_irrigation_at'),
    weather_cache: wc ? {
        ...wc,
        age_seconds: weather_age_s,
        available: weather_age_s !== null && weather_age_s * 1000 < (cfg.weather.cache_max_age_seconds * 1000)
    } : null,
    sensors_cached: Object.keys(global.get('soil_moisture_cache') || {}).length,
    last_decision_at: global.get('last_decision_at'),
    last_decision_outcome: global.get('last_decision_outcome')
};
return msg;

// Decide se è ora di pollare Open-Meteo.
const cfg = global.get('irrigation_config');
if (!cfg) return null;
const now = Date.now();
const last = global.get('last_weather_poll_at') || 0;
const interval_ms = (cfg.weather.polling_interval_seconds || 1800) * 1000;
if ((now - last) < interval_ms) return null;

global.set('last_weather_poll_at', now);

const lat = cfg.weather.lat;
const lon = cfg.weather.lon;
if (typeof lat !== 'number' || typeof lon !== 'number') {
    node.warn('weather.lat/lon non configurati, skip polling');
    return null;
}

const url = `${cfg.weather.api_url}?latitude=${lat}&longitude=${lon}&hourly=precipitation,temperature_2m,relative_humidity_2m&forecast_days=2&timezone=Europe%2FRome`;
msg.url = url;
msg.method = 'GET';
msg._t0 = now;
node.status({ fill: 'blue', shape: 'dot', text: `polling @ ${new Date().toISOString().substr(11, 8)}` });
return msg;

// Parse risposta Open-Meteo, calcola scalari, aggiorna cache, prepara point.
const body = msg.payload;
const t0 = msg._t0 || Date.now();
const latency_ms = Date.now() - t0;

if (msg.statusCode !== 200 || !body || !body.hourly) {
    node.warn(`Open-Meteo fail: status=${msg.statusCode}`);
    node.status({ fill: 'red', shape: 'ring', text: `fail ${msg.statusCode || '-'}` });
    return null;
}

const h = body.hourly;
const precip = Array.isArray(h.precipitation) ? h.precipitation : [];
const temp = Array.isArray(h.temperature_2m) ? h.temperature_2m : [];
const hum = Array.isArray(h.relative_humidity_2m) ? h.relative_humidity_2m : [];

const sum = (arr, n) => arr.slice(0, n).reduce((a, v) => a + (Number.isFinite(v) ? v : 0), 0);
const maxN = (arr, n) => {
    const slice = arr.slice(0, n).filter(Number.isFinite);
    return slice.length ? Math.max(...slice) : 0;
};

const data = {
    precip_next_24h_mm: Number(sum(precip, 24).toFixed(2)),
    precip_next_6h_mm: Number(sum(precip, 6).toFixed(2)),
    temp_max_next_12h_c: Number(maxN(temp, 12).toFixed(1)),
    humidity_now_pct: Number((hum[0] || 0).toFixed(1)),
    api_latency_ms: latency_ms,
    fetched_at: Date.now()
};

global.set('weather_cache', data);
node.status({ fill: 'green', shape: 'dot', text: `rain24h=${data.precip_next_24h_mm}mm @ ${new Date().toISOString().substr(11, 5)}` });

return {
    payload: [
        {
            precip_next_24h_mm: data.precip_next_24h_mm,
            precip_next_6h_mm: data.precip_next_6h_mm,
            temp_max_next_12h_c: data.temp_max_next_12h_c,
            humidity_now_pct: data.humidity_now_pct,
            api_latency_ms: data.api_latency_ms
        },
        { source: 'openmeteo', location: 'orto' }
    ],
    measurement: 'weather_forecast'
};

// Risolve uno dei 5 scenari (vedi step4 §9).
// Input msg.payload: array di righe Flux (oggetti con _field, _value, _time).
const rows = Array.isArray(msg.payload) ? msg.payload : (Array.isArray(msg.payload && msg.payload[0]) ? msg.payload[0] : []);
const valve = global.get('valve_state_runtime');
const in_progress = !!global.get('in_progress');
const opened_at = global.get('opened_at');
const cfg = global.get('irrigation_config') || {};
const safetyMs = ((cfg.irrigation && cfg.irrigation.safety_timeout_seconds) || 900) * 1000;
const now = Date.now();

// Aggrega l'ultimo evento (Flux ritorna 1 riga per field).
let lastEvent = null;
if (Array.isArray(rows) && rows.length) {
    const byTime = {};
    for (const r of rows) {
        const t = r._time;
        if (!byTime[t]) byTime[t] = { _time: t, fields: {} };
        byTime[t].fields[r._field] = r._value;
    }
    const sorted = Object.values(byTime).sort((a, b) => new Date(b._time) - new Date(a._time));
    lastEvent = sorted[0];
}

let scenario = 'unknown';
let outMsgs = [];

const lastEventState = lastEvent && lastEvent.fields ? lastEvent.fields.state : null;
const lastEventTime = lastEvent ? new Date(lastEvent._time).getTime() : null;
const lastEventAge = lastEventTime ? (now - lastEventTime) : null;

// Hot-reload: se in_progress è già coerente in global, non interferire.
if (in_progress && opened_at && (now - opened_at) < safetyMs) {
    scenario = 'already_tracked_by_runtime';
    node.warn(`[recovery] scenario=${scenario} (in_progress=true, age=${Math.round((now-opened_at)/1000)}s) — no action`);
    node.status({ fill: 'green', shape: 'ring', text: scenario });
    return [null, null];
}

// MQTT non ha ancora pubblicato stato: defer (no action).
if (valve === undefined || valve === null) {
    scenario = 'deferred_no_mqtt_state';
    node.warn(`[recovery] scenario=${scenario} (valve_state non ricevuto da Z2M, lastEvent=${lastEventState}) — no action, ricalcolo al prossimo tick di decisione`);
    node.status({ fill: 'grey', shape: 'ring', text: scenario });
    return [null, null];
}

if (valve === 'OFF' && (!lastEvent || lastEventState === 'OFF' || lastEventState === undefined)) {
    scenario = 'normal';
    global.set('in_progress', false);
} else if (valve === 'ON' && lastEventState === 'ON' && lastEventAge !== null && lastEventAge < safetyMs) {
    scenario = 'recovery_in_progress';
    global.set('in_progress', true);
    global.set('opened_at', lastEventTime);
    global.set('target_duration_seconds', (cfg.irrigation && cfg.irrigation.safety_timeout_seconds) || 900);
} else if (valve === 'ON' && lastEventState === 'ON' && lastEventAge !== null && lastEventAge >= safetyMs) {
    scenario = 'recovery_timeout';
    outMsgs.push({ topic: 'zigbee2mqtt/SWV_valvola/set', payload: { state: 'OFF' }, _recovery: true });
    outMsgs.push({
        payload: [
            { state: 'OFF', duration_seconds: Math.round(lastEventAge / 1000), reason: 'recovery_timeout' },
            { trigger: 'orphan_recovery', valve_id: 'SWV_01' }
        ],
        measurement: 'irrigation_events'
    });
    global.set('in_progress', false);
} else if (valve === 'ON' && (lastEventState === 'OFF' || !lastEvent)) {
    scenario = 'orphan_valve_on';
    outMsgs.push({ topic: 'zigbee2mqtt/SWV_valvola/set', payload: { state: 'OFF' }, _recovery: true });
    outMsgs.push({
        payload: [
            { state: 'OFF', duration_seconds: 0, reason: 'orphan_recovery' },
            { trigger: 'orphan_recovery', valve_id: 'SWV_01' }
        ],
        measurement: 'irrigation_events'
    });
    global.set('in_progress', false);
} else if (valve === 'OFF' && lastEventState === 'ON') {
    scenario = 'recovery_lost';
    outMsgs.push({
        payload: [
            { state: 'OFF', duration_seconds: lastEventAge ? Math.round(lastEventAge / 1000) : 0, reason: 'recovery_lost' },
            { trigger: 'orphan_recovery', valve_id: 'SWV_01' }
        ],
        measurement: 'irrigation_events'
    });
    global.set('in_progress', false);
} else {
    scenario = `unhandled (valve=${valve}, lastEvent=${lastEventState})`;
    global.set('in_progress', false);
}

node.warn(`[recovery] scenario=${scenario}`);
node.status({ fill: scenario === 'normal' ? 'green' : 'yellow', shape: 'dot', text: scenario });

// Output 1: comandi MQTT (force close), Output 2: punti InfluxDB (eventi anomali)
const mqttOuts = outMsgs.filter(m => m.topic);
const influxOuts = outMsgs.filter(m => m.measurement);
return [mqttOuts.length ? mqttOuts : null, influxOuts.length ? influxOuts : null];

// Dispatcher 60s. Branch in_progress -> monitoring, altrimenti -> decision.
const cfg = global.get('irrigation_config');
if (!cfg) { node.status({ fill: 'grey', shape: 'ring', text: 'no config' }); return null; }

// Auto-resume da pausa scaduta
if (cfg.pause_until && new Date(cfg.pause_until).getTime() <= Date.now()) {
    cfg.pause_until = null;
    global.set('irrigation_config', cfg);
    node.warn('pause_until expired, resuming auto');
}

const in_progress = !!global.get('in_progress');
if (in_progress) return [null, msg]; // monitoring branch

const now = Date.now();
const last = global.get('last_decision_at') || 0;
const interval_ms = (cfg.irrigation.polling_interval_seconds || 300) * 1000;
if ((now - last) < interval_ms) return null;
global.set('last_decision_at', now);
return [msg, null]; // decision branch

// Algoritmo step 4 §7. Output:
//  [0] mqtt out (publish ON su zigbee2mqtt o mock)
//  [1] influxdb out (skip event o open event)
//  [2] debug status
const cfg = global.get('irrigation_config');
if (!cfg) return null;
const now = Date.now();

function sensorStats() {
    const cache = global.get('soil_moisture_cache') || {};
    const max_age_ms = cfg.sensors.max_age_seconds * 1000;
    const valid = Object.values(cache).filter(e => (now - e.ts) < max_age_ms).map(e => e.value);
    if (valid.length < cfg.sensors.min_quorum) return { count: valid.length, mean: null, stddev: 0, high_var: false };
    const mean = valid.reduce((a, b) => a + b, 0) / valid.length;
    const variance = valid.reduce((s, v) => s + (v - mean) ** 2, 0) / valid.length;
    const stddev = Math.sqrt(variance);
    return { count: valid.length, mean: Number(mean.toFixed(2)), stddev: Number(stddev.toFixed(2)), high_var: stddev > cfg.sensors.stddev_warning_pct };
}

function inWindow(date, win) {
    const hh = date.getHours().toString().padStart(2, '0');
    const mm = date.getMinutes().toString().padStart(2, '0');
    const cur = `${hh}:${mm}`;
    return cur >= win[0] && cur < win[1];
}

function inAnyWindow(date) {
    return inWindow(date, cfg.irrigation.finestra_mattina) || inWindow(date, cfg.irrigation.finestra_sera);
}

function weatherInfo() {
    const wc = global.get('weather_cache');
    if (!wc || !wc.fetched_at) return { available: false, age: 0, rain_24h: 0 };
    const age = now - wc.fetched_at;
    return {
        available: age < cfg.weather.cache_max_age_seconds * 1000,
        age: Math.round(age / 1000),
        rain_24h: wc.precip_next_24h_mm || 0
    };
}

function skipEvent(reason, ctx) {
    return {
        payload: [
            {
                state: 'SKIP',
                duration_seconds: 0,
                avg_moisture_at_trigger: ctx.sensors.mean || 0,
                skip_reason: reason,
                rain_forecast_mm: ctx.weather.rain_24h,
                weather_data_age_seconds: ctx.weather.age,
                weather_available: ctx.weather.available,
                sensor_count: ctx.sensors.count,
                sensors_high_variance: ctx.sensors.high_var,
                dry_run: cfg.mode === 'dry_run'
            },
            { trigger: 'skip', valve_id: 'SWV_01' }
        ],
        measurement: 'irrigation_events'
    };
}

const sensors = sensorStats();
const weather = weatherInfo();
const ctx = { sensors, weather };

// 1) Pause / mode
if (cfg.mode === 'paused' || (cfg.pause_until && new Date(cfg.pause_until).getTime() > now)) {
    global.set('last_decision_outcome', 'skip:paused');
    node.status({ fill: 'grey', shape: 'dot', text: 'paused' });
    return [null, skipEvent('paused', ctx), null];
}

// 2) Quorum sensori
if (sensors.count < cfg.sensors.min_quorum) {
    global.set('last_decision_outcome', 'skip:no_quorum');
    node.status({ fill: 'red', shape: 'ring', text: `no_quorum (${sensors.count})` });
    return [null, skipEvent('no_quorum', ctx), null];
}

// 3) Umidità sufficiente: nessun log evento (no "non-decisione")
if (sensors.mean >= cfg.irrigation.soglia_apertura_pct) {
    global.set('last_decision_outcome', `ok:moist=${sensors.mean}`);
    node.status({ fill: 'green', shape: 'dot', text: `moist=${sensors.mean}% (>=${cfg.irrigation.soglia_apertura_pct})` });
    return null;
}

const is_emergency = sensors.mean < cfg.irrigation.soglia_emergenza_pct;

// 4) Orario (saltato se emergenza)
if (!is_emergency && !inAnyWindow(new Date(now))) {
    global.set('last_decision_outcome', 'skip:out_of_window');
    node.status({ fill: 'grey', shape: 'dot', text: 'out_of_window' });
    return [null, skipEvent('out_of_window', ctx), null];
}

// 5) Cooldown (sempre)
const last_irr = global.get('last_irrigation_at') || 0;
if ((now - last_irr) < cfg.irrigation.cooldown_seconds * 1000) {
    global.set('last_decision_outcome', 'skip:cooldown');
    node.status({ fill: 'grey', shape: 'dot', text: 'cooldown' });
    return [null, skipEvent('cooldown', ctx), null];
}

// 6) Pioggia (solo se cache disponibile)
if (weather.available && weather.rain_24h >= cfg.weather.rain_threshold_mm) {
    global.set('last_decision_outcome', `skip:rain_delay(${weather.rain_24h}mm)`);
    node.status({ fill: 'blue', shape: 'dot', text: `rain_delay (${weather.rain_24h}mm)` });
    return [null, skipEvent('rain_delay', ctx), null];
}

// 7) Reachable check
if (global.get('valve_reachable') === false) {
    const counter = (global.get('valve_unreachable_consecutive') || 0) + 1;
    global.set('valve_unreachable_consecutive', counter);
    if (counter >= cfg.valve.unreachable_alert_after) {
        node.warn(`[ALERT] valve unreachable for ${counter} consecutive ticks`);
    }
    global.set('last_decision_outcome', `skip:valve_unreachable(${counter})`);
    node.status({ fill: 'red', shape: 'dot', text: `unreachable x${counter}` });
    return [null, skipEvent('valve_unreachable', ctx), null];
}

// 8) APRI
const trigger = is_emergency ? 'emergency' : 'auto';
const target_duration = is_emergency ? cfg.irrigation.emergency_duration_seconds : cfg.irrigation.safety_timeout_seconds;

global.set('last_cmd_source', trigger);
global.set('target_duration_seconds', target_duration);
global.set('last_decision_outcome', `open:${trigger}@${sensors.mean}%`);

const topic = cfg.mode === 'dry_run' ? 'orto/dryrun/valve/set' : 'zigbee2mqtt/SWV_valvola/set';
node.warn(`[DECISION] open trigger=${trigger} mean=${sensors.mean}% mode=${cfg.mode} target=${target_duration}s`);
node.status({ fill: 'yellow', shape: 'dot', text: `OPEN ${trigger} ${sensors.mean}%` });

const openMsg = { topic, payload: { state: 'ON' } };

// In dry_run, simuliamo l'apertura senza aspettare conferma valvola reale.
// Pubblichiamo subito il record di apertura su irrigation_events e settiamo in_progress.
if (cfg.mode === 'dry_run') {
    global.set('in_progress', true);
    global.set('opened_at', now);
    global.set('irrigation_open', {
        ts: now,
        avg_at_trigger: sensors.mean,
        sensor_count: sensors.count,
        sensors_high_variance: sensors.high_var,
        rain_forecast_mm: weather.rain_24h,
        weather_data_age_seconds: weather.age,
        weather_available: weather.available,
        trigger,
        dry_run: true
    });
    const openEvent = {
        payload: [
            {
                state: 'ON',
                duration_seconds: 0,
                avg_moisture_at_trigger: sensors.mean,
                rain_forecast_mm: weather.rain_24h,
                weather_data_age_seconds: weather.age,
                weather_available: weather.available,
                sensor_count: sensors.count,
                sensors_high_variance: sensors.high_var,
                dry_run: true,
                reason: trigger
            },
            { trigger, valve_id: 'SWV_01' }
        ],
        measurement: 'irrigation_events'
    };
    return [openMsg, openEvent, null];
}

// Mode auto: il publish va sul topic reale; il tracking ON/OFF avviene
// in n-fn-valve-irrigation-event al ritorno di stato dalla valvola.
return [openMsg, null, null];

// Tick durante irrigazione: chiude se soglia raggiunta o timeout.
const cfg = global.get('irrigation_config');
if (!cfg) return null;
const now = Date.now();
const opened_at = global.get('opened_at') || now;
const target = global.get('target_duration_seconds') || cfg.irrigation.safety_timeout_seconds;
const elapsed_s = (now - opened_at) / 1000;

function sensorStats() {
    const cache = global.get('soil_moisture_cache') || {};
    const max_age_ms = cfg.sensors.max_age_seconds * 1000;
    const valid = Object.values(cache).filter(e => (now - e.ts) < max_age_ms).map(e => e.value);
    if (valid.length < cfg.sensors.min_quorum) return { count: valid.length, mean: null };
    const mean = valid.reduce((a, b) => a + b, 0) / valid.length;
    return { count: valid.length, mean: Number(mean.toFixed(2)) };
}

const sensors = sensorStats();
let shouldClose = null;
if (sensors.mean !== null && sensors.mean > cfg.irrigation.soglia_chiusura_pct) shouldClose = 'threshold_reached';
if (elapsed_s > target) shouldClose = 'safety_timeout';

if (!shouldClose) {
    node.status({ fill: 'yellow', shape: 'dot', text: `irrigating ${Math.round(elapsed_s)}s mean=${sensors.mean}` });
    return null;
}

const topic = cfg.mode === 'dry_run' ? 'orto/dryrun/valve/set' : 'zigbee2mqtt/SWV_valvola/set';
node.warn(`[MONITORING] close reason=${shouldClose} elapsed=${Math.round(elapsed_s)}s mean=${sensors.mean}`);
node.status({ fill: 'green', shape: 'dot', text: `CLOSE ${shouldClose}` });

const closeMqtt = { topic, payload: { state: 'OFF' } };

// In dry_run scriviamo il record di chiusura qui (n-fn-valve-irrigation-event
// non riceverà l'evento OFF dalla valvola reale).
if (cfg.mode === 'dry_run') {
    const open = global.get('irrigation_open') || {};
    const duration_s = Math.round(elapsed_s);
    const delta = (sensors.mean !== null && open.avg_at_trigger != null) ? Number((sensors.mean - open.avg_at_trigger).toFixed(2)) : 0;
    global.set('irrigation_open', null);
    global.set('in_progress', false);
    global.set('opened_at', null);
    global.set('last_irrigation_at', now);
    global.set('last_cmd_source', null);
    const closeEvent = {
        payload: [
            {
                state: 'OFF',
                duration_seconds: duration_s,
                avg_moisture_at_trigger: open.avg_at_trigger || 0,
                avg_moisture_at_close: sensors.mean || 0,
                delta_moisture: delta,
                reason: shouldClose,
                rain_forecast_mm: open.rain_forecast_mm || 0,
                weather_data_age_seconds: open.weather_data_age_seconds || 0,
                weather_available: !!open.weather_available,
                sensor_count: sensors.count,
                dry_run: true
            },
            { trigger: open.trigger || 'auto', valve_id: 'SWV_01' }
        ],
        measurement: 'irrigation_events'
    };
    return [closeMqtt, closeEvent];
}

return [closeMqtt, null];

msg.query = `from(bucket:"garden")
  |> range(start: -2h)
  |> filter(fn:(r) => r._measurement == "soil_moisture")
  |> last()
  |> pivot(rowKey:["_time"], columnKey:["_field"], valueColumn:"_value")`;
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : (msg.payload && msg.payload[0] ? msg.payload[0] : []);
const flat = [];
(Array.isArray(rows) ? rows : [rows]).forEach(r => {
    if (Array.isArray(r)) r.forEach(x => flat.push(x));
    else if (r && typeof r === 'object') flat.push(r);
});
const now = Date.now();
const SENSOR_IDS = ['WH51_01','WH51_02','WH51_03','WH51_04','WH51_05','WH51_06'];
const result = SENSOR_IDS.map(id => {
    const r = flat.find(x => x && x.sensor_id === id);
    if (!r) return { sensor_id: id, aiuola: null, position: null, value: null, timestamp: null, battery_ok: null, rssi: null, online: false };
    const t = r._time ? new Date(r._time).getTime() : null;
    return {
        sensor_id: id,
        aiuola: r.aiuola || null,
        position: r.position || null,
        value: Number.isFinite(r.value) ? Number(r.value) : null,
        timestamp: t,
        battery_ok: typeof r.battery_ok === 'boolean' ? r.battery_ok : (Number(r.battery_voltage) > 1.5),
        rssi: Number.isFinite(r.rssi) ? Number(r.rssi) : null,
        online: t ? (now - t) < 30 * 60 * 1000 : false
    };
});
msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = result;
return msg;

const params = (msg.req && msg.req.query) || {};
const start = params.start || '-24h';
const stop = params.stop || 'now()';
// aggregation auto: <=6h raw, <=7d 5m, oltre 1h
function parseRange(s) {
    const m = String(s).match(/^-(\d+)([smhd])$/);
    if (!m) return null;
    const n = Number(m[1]);
    const unit = { s: 1, m: 60, h: 3600, d: 86400 }[m[2]] || 0;
    return n * unit;
}
const sec = parseRange(start);
let every;
if (params.every) every = params.every;
else if (!sec || sec <= 6 * 3600) every = null;
else if (sec <= 7 * 86400) every = '5m';
else every = '1h';

const filter_sensor = params.sensor_id ? `\n  |> filter(fn:(r) => r.sensor_id == "${params.sensor_id}")` : '';
const agg = every ? `\n  |> aggregateWindow(every: ${every}, fn: mean, createEmpty: false)` : '';

msg.query = `from(bucket:"garden")
  |> range(start: ${start}, stop: ${stop})
  |> filter(fn:(r) => r._measurement == "soil_moisture" and r._field == "value")${filter_sensor}${agg}
  |> keep(columns: ["_time","_value","sensor_id"])`;
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const flat = [];
rows.forEach(r => { if (Array.isArray(r)) r.forEach(x => flat.push(x)); else if (r) flat.push(r); });
const result = {};
flat.forEach(r => {
    const id = r.sensor_id || 'unknown';
    if (!result[id]) result[id] = [];
    result[id].push({ t: r._time ? new Date(r._time).getTime() : null, value: Number(r._value) });
});
msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = result;
return msg;

const params = (msg.req && msg.req.query) || {};
const start = params.start || '-7d';
const stop = params.stop || 'now()';
msg.query = `from(bucket:"garden")
  |> range(start: ${start}, stop: ${stop})
  |> filter(fn:(r) => r._measurement == "irrigation_events" and (r._field == "duration_seconds" or r._field == "state"))
  |> pivot(rowKey:["_time","trigger","valve_id"], columnKey:["_field"], valueColumn:"_value")
  |> sort(columns: ["_time"])`;
return msg;

// irrigation_events viene scritto solo a OFF con duration_seconds = durata intervallo.
// Costruiamo gli intervalli: end = _time, start = end - duration_seconds, trigger = tag.
const rows = Array.isArray(msg.payload) ? msg.payload : [];
const flat = [];
rows.forEach(r => { if (Array.isArray(r)) r.forEach(x => flat.push(x)); else if (r) flat.push(r); });
const result = flat
    .filter(r => r && r.state === 'OFF' && Number.isFinite(r.duration_seconds) && r.duration_seconds > 0)
    .map(r => {
        const end = new Date(r._time).getTime();
        const start = end - (Number(r.duration_seconds) * 1000);
        return {
            start,
            end,
            duration_seconds: Number(r.duration_seconds),
            trigger: r.trigger || 'unknown'
        };
    })
    .sort((a, b) => b.start - a.start);
msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = result;
return msg;

const params = (msg.req && msg.req.query) || {};
const start = params.start || '-7d';
const stop = params.stop || 'now()';
msg.query = `from(bucket:"garden")
  |> range(start: ${start}, stop: ${stop})
  |> filter(fn:(r) => r._measurement == "irrigation_events" and r._field == "duration_seconds")
  |> sum()`;
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const flat = [];
rows.forEach(r => { if (Array.isArray(r)) r.forEach(x => flat.push(x)); else if (r) flat.push(r); });
const total = flat.reduce((acc, r) => acc + (Number(r && r._value) || 0), 0);
msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = { total_open_seconds: Math.round(total) };
return msg;

msg.query = `from(bucket:"garden")
  |> range(start: -2h)
  |> filter(fn:(r) => r._measurement == "weather_forecast")
  |> last()
  |> pivot(rowKey:["_time"], columnKey:["_field"], valueColumn:"_value")`;
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const flat = [];
rows.forEach(r => { if (Array.isArray(r)) r.forEach(x => flat.push(x)); else if (r) flat.push(r); });
const r = flat[0] || {};
msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = {
    temperature_c: Number.isFinite(r.temp_max_next_12h_c) ? Number(r.temp_max_next_12h_c) : null,
    humidity_pct: Number.isFinite(r.humidity_now_pct) ? Number(r.humidity_now_pct) : null,
    precip_next_24h_mm: Number.isFinite(r.precip_next_24h_mm) ? Number(r.precip_next_24h_mm) : null,
    precip_next_6h_mm: Number.isFinite(r.precip_next_6h_mm) ? Number(r.precip_next_6h_mm) : null,
    timestamp: r._time ? new Date(r._time).getTime() : null,
    source: 'openmeteo'
};
return msg;

const cfg = global.get('irrigation_config') || {};
const lat = (cfg.weather && cfg.weather.lat) || 44.4;
const lon = (cfg.weather && cfg.weather.lon) || 11.3;
const base = (cfg.weather && cfg.weather.api_url) || 'https://api.open-meteo.com/v1/forecast';
msg.url = `${base}?latitude=${lat}&longitude=${lon}&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,weather_code&forecast_days=7&timezone=Europe%2FRome`;
msg.method = 'GET';
return msg;

const p = msg.payload || {};
const d = p.daily || {};
const result = [];
const dates = d.time || [];
for (let i = 0; i < dates.length; i++) {
    result.push({
        date: dates[i],
        t_min: d.temperature_2m_min ? Number(d.temperature_2m_min[i]) : null,
        t_max: d.temperature_2m_max ? Number(d.temperature_2m_max[i]) : null,
        precip_mm: d.precipitation_sum ? Number(d.precipitation_sum[i]) : null,
        weather_code: d.weather_code ? Number(d.weather_code[i]) : null
    });
}
msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = result;
return msg;

const now = Date.now();
let startup_at = global.get('nodered_startup_at');
if (!startup_at) { startup_at = now; global.set('nodered_startup_at', startup_at); }
const uptime_seconds = Math.floor((now - startup_at) / 1000);
const valve_state = global.get('valve_state_runtime') || 'unknown';
const valve_reachable = global.get('valve_reachable');
const last_weather_poll = global.get('last_weather_poll_at') || 0;
const sensors_cache = global.get('soil_moisture_cache') || {};
const sensors_online = Object.values(sensors_cache).filter(e => e && (now - e.ts) < 30 * 60 * 1000).length;
const cfg = global.get('irrigation_config');

msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = {
    uptime_seconds,
    timestamp: now,
    config_loaded: !!cfg,
    mode: cfg ? cfg.mode : null,
    valve_state,
    valve_reachable: typeof valve_reachable === 'boolean' ? valve_reachable : null,
    sensors_online,
    sensors_total: 6,
    weather_last_poll_seconds_ago: last_weather_poll ? Math.round((now - last_weather_poll) / 1000) : null
};
return msg;

// Richiede body { confirm: 'shutdown' } per evitare azioni accidentali.
const body = msg.req && msg.req.body;
if (!body || body.confirm !== 'shutdown') {
    msg.statusCode = 400;
    msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
    msg.payload = { ok: false, error: "missing confirm: 'shutdown' in body" };
    return [null, msg];
}
node.warn('Shutdown richiesto da API');
// Pattern file-flag: il container Alpine non puo' eseguire shutdown.
// Scrive flag in /data/system/shutdown_requested.flag (mounted come
// /opt/orto-digitale/nodered/data/system/ sull'host). Il systemd
// service 'orto-shutdown-watcher' monitora il file ed esegue sudo
// /sbin/shutdown -h +1 sull'host.
msg.payload = JSON.stringify({ requested_at: Date.now(), source: 'api', reason: 'PWA shutdown' });
return [msg, null];

msg.statusCode = 200;
msg.headers = { 'Access-Control-Allow-Origin': '*', 'Content-Type': 'application/json' };
msg.payload = { ok: true, scheduled_in_seconds: 60, message: 'Shutdown flag written. Host watcher will trigger shutdown -h +1. Cancel: ssh + sudo shutdown -c' };
return msg;
